import { useEffect, useState } from "react";
import { ToastProvider } from "./components/ToastContext.jsx";
import { Routes, Route, useParams, Navigate, Outlet } from "react-router-dom";
import Header from "./components/Header.jsx";
import ModalLogin from "./components/ModalLogin.jsx";
import ModalUser from "./components/ModalUser.jsx";
import Home from "./components/Home.jsx";
import Contact from "./components/Contact.jsx";
import Setting from "./components/Setting.jsx";
import KhoiKinhThanh from "./components/KhoiKinhThanh.jsx";
import KhoiPhungVu from "./components/KhoiPhungVu.jsx";
import KhoiThemSuc from "./components/KhoiThemSuc.jsx";
import TaiLieu from "./components/TaiLieu.jsx";
import TestQuiz from "./components/TestQuiz.jsx";
import Footer from "./components/Footer.jsx";
import useAutoBackground from "./hooks/useAutoBackground";
import "./App.css";

const fontSizeMap = {
  sm: "text-sm",
  base: "text-base",
  lg: "text-lg",
  xl: "text-xl",
};

function App() {
  const [fontSize, setFontSize] = useState("base");
  const [turnOnModal, setTurnOnModal] = useState(false);
  const [isLogin, setIsLogin] = useState(false);

  useAutoBackground();

  const toggleModal = () => {
    setTurnOnModal(true);
  }

  useEffect(()=>{
    const username = localStorage.getItem("username");
    if(username) setIsLogin(true);
  },[]);

  useEffect(() => {
    if (turnOnModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }

    return () => {
      document.body.style.overflow = "";
    };
  }, [turnOnModal]);

  const handleClose = () => {
    setTurnOnModal(false);
  }

  return (
    <ToastProvider>
      <Routes>
        {/* Layout có Header + Footer */}
        <Route
          element={
            <div className={fontSizeMap[fontSize]}>
              <Header
                toggleModal={toggleModal}
                isLogin={isLogin}
              />
              <main className="container mx-auto px-4">
                <Outlet />
              </main>
              <Footer />
            </div>
          }
        >
          <Route index element={<Home />} />
          <Route path="khoi-kinh-thanh" element={<KhoiKinhThanh />} />
          <Route path="khoi-phung-vu" element={<KhoiPhungVu />} />
          <Route path="khoi-them-suc" element={<KhoiThemSuc />} />
          <Route path="tai-lieu-on-tap" element={<TaiLieu />} />
          <Route path="lien-he" element={<Contact />} />
          <Route path="cai-dat" element={<Setting />} />

        </Route>

        {/* Quiz KHÔNG có Header / Footer */}
        <Route
          path="/:khoi/:type"
          element={<TestQuiz />}
        />

      </Routes>   

      {!isLogin && turnOnModal && <ModalLogin handleClose={handleClose} setIsLogin={setIsLogin}/>}
      {isLogin && turnOnModal && <ModalUser setIsLogin={setIsLogin} handleClose={handleClose}/>} 
    </ToastProvider>
  );
}

export default App;
