import { useState, useEffect, useRef } from "react";
export function Loading(){
  return (
    <div id="doc-loading" className="flex flex-col items-center justify-center py-20 text-neutral-400">
      <svg className="animate-spin h-6 w-6 text-orange-500 mb-3" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v4a4 4 0 00-4 4H4z"></path>
      </svg>
      <span className="text-xs font-medium">Đang tải dữ liệu...</span>
    </div>
  )
}
export default function TaiLieu() {
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadingContent, setIsLoadingContent] = useState(false);
  const [items, setItems] = useState([]);
  const [data, setData] = useState([]);
  const [openIds, setOpenIds] = useState([]);
  const [error, setError] = useState(null);
  const [isEmpty, setIsEmpty] = useState(false);
  const [active, setActive] = useState('all');
  const API_URL = "https://script.google.com/macros/s/AKfycbzum9kVRG0GCqzTUNLls1WVyUt9fzpGRWZ3Rn7gWaueCNOeBOszVckEF_P9-2645gWm/exec"; // 🔴 đổi URL GAS
  const DOC_CACHE_TTL = 6 * 60 * 60 * 1000; // 6 tiếng (phải khớp server)

  const mapCategory = {
    "15p_hk1": "15 Phút",
    "1tiet_hk1": "1 Tiết",
    "hk1": "Thi HK",
    "15p_hk2": "15 Phút",
    "1tiet_hk2": "1 Tiết",
    "hk2": "Thi HK"
  };

  function getDocCacheKey(cat) {
    return `DOCS_${cat || "all"}`;
  }

  function getCachedDocs(cat) {
    const key = getDocCacheKey(cat);
    const raw = localStorage.getItem(key);
    if (!raw) return null;

    try {
      const { data, time } = JSON.parse(raw);
      if (Date.now() - time > DOC_CACHE_TTL) {
        localStorage.removeItem(key);
        return null;
      }
      return data;
    } catch {
      localStorage.removeItem(key);
      return null;
    }
  }

  function setCachedDocs(cat, data) {
    const key = getDocCacheKey(cat);
    localStorage.setItem(
      key,
      JSON.stringify({
        data,
        time: Date.now()
      })
    );
  }

  async function loadDocuments(cat) {

    setIsLoading(true);

    // 🔥 1. Try cache first
    const cached = getCachedDocs(cat);
    if (cached) {
      setItems(cached);
      setIsLoading(false);
      return;
    }
    try {
      const res = await fetch(`${API_URL}?path=DOCS&cat=${cat}`);
      const data = await res.json();
      // 🔥 2. Save cache
      if(cat==="all"){
        data.forEach(d=>setCachedDocs(d.cat,[d]));
      }
      setCachedDocs(cat, data);
      setItems(data);
    } catch (err) {
      console.error(err);
      setIsEmpty(true);
    } setIsLoading(false);
  }
  /* ================= RENDER DOCUMENTS ================= */
  function renderDocs(items) {
    if (!items || items.length === 0) {
      return;
    }

    return items.map(doc => {
      const catText = mapCategory[doc.cat] ?? doc.cat.toUpperCase();
      const CAT_CLASS_MAP = {
        "15p_hk1": "text-emerald-600 bg-emerald-50",
        "1tiet_hk1":   "text-purple-600 bg-purple-50",
        "hk1": "text-red-600 bg-red-50",
        "15p_hk2": "text-emerald-600 bg-emerald-50",
        "1tiet_hk2":   "text-purple-600 bg-purple-50",
        "hk2": "text-red-600 bg-red-50",
      };
      const catClass = CAT_CLASS_MAP[doc.cat] || "text-neutral-600 bg-neutral-100";
      const isOpen = openIds.includes(doc.id);

      return (
        <div className="doc-item bg-white rounded-xl border border-gray-100 overflow-hidden">
          
          {/* <!-- HEADER --> */}
          <div className="doc-header group cursor-pointer flex justify-between gap-3 p-4"
               onClick={()=>handleToggle(doc.id)}>

            <div className="flex flex-col gap-1 w-full">
              <div className="flex items-center gap-2 mb-1">
                <span className={`text-[12px] font-bold px-1.5 py-0.5 rounded ${catClass}`}>
                  {catText}
                </span>

              </div>

              <span className="text-lg font-medium text-gray-900 leading-snug
                           group-hover:text-indigo-600 transition-colors">
                {doc.title}
              </span>

              <span className="text-sm text-gray-400">
                {doc.description} · {doc.updatedAt}
              </span>
            </div>

            <svg className={`${isOpen?"rotate-180":""} icon-chevron w-5 h-5 text-gray-400 transition-transform duration-200 mt-1 flex-shrink-0`}
                 viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
              <polyline points="6 9 12 15 18 9"></polyline>
            </svg>
          </div>

          {/* <!-- CONTENT --> */}
          {isOpen && <div className="doc-content border-t border-gray-50 p-4">
            {!isLoadingContent && <div className="text-sm text-gray-400">Đang tải nội dung...</div>}
            {error && <p className="text-red-500 text-sm">{error}</p>}
            {data.filter(d => d.id === doc.id).map(d => renderExamContent(d.mcq, d.essay))}
          </div>}

        </div>
      )
    });
  }

  const handleToggle = async (docId) => {
    setOpenIds(prev => prev.includes(docId) ? prev.filter(id => id !== docId) : [...prev, docId]);

    try {
      const res = await fetch(`${API_URL}?path=DOC_QUESTIONS&docId=${docId}`);
      const json = await res.json();

      setData(prev => 
      {
        if(prev.some(p=>p.id===docId)) return prev;
        return [...prev, { id: docId, ...json }];
      });
    } catch (err) {
      setError("Lỗi tải nội dung");
    }
    setIsLoadingContent(true);
  };

  function renderExamContent(mcq, essay) {
    if (mcq?.length || essay?.length) {
      return (
        <>
        <section className="mb-6">
          {/* <!-- HEADER --> */}
          <div className="flex items-center justify-between mb-3">
            <h4 className="text-base font-bold text-orange-700 flex items-center gap-2">
              📝 Trắc nghiệm
            </h4>
            <span className="text-xs px-2 py-0.5 rounded-full bg-orange-100 text-orange-700 font-semibold">
              {mcq.length} câu
            </span>
          </div>

          {/* <!-- QUESTIONS --> */}
          <div className="space-y-4">
            {mcq.map((q, index) => 
              <div className="bg-white border border-neutral-200 rounded-xl p-4 shadow-sm hover:shadow transition">
                
                {/* <!-- QUESTION --> */}
                <p className="text-sm font-semibold text-neutral-800 mb-3">
                  Câu {index + 1}. {q.question}
                </p>

                {/* <!-- OPTIONS --> */}
                <ul className="space-y-2 text-sm">
                  {q.options.map((choice, i) => {
                    const letter = String.fromCharCode(65 + i);
                    const isCorrect = q.answer === letter;

                    return (
                      <li className={`flex items-start gap-3 px-3 py-2 rounded-lg
                        ${isCorrect
                          ? "bg-emerald-50 text-emerald-700 border border-emerald-200"
                          : "bg-neutral-50 text-neutral-600"}`}>
                        <span className={`flex items-center justify-center w-6 h-6 rounded-full text-xs font-bold
                          ${isCorrect
                            ? "bg-emerald-600 text-white"
                            : "bg-neutral-200 text-neutral-700"}`}>
                          {letter}
                        </span>
                        <span className="flex-1">{choice}</span>
                        {isCorrect && <span className="text-emerald-600 font-bold">✓</span>}
                      </li>
                    )
                  })}
                </ul>
              </div>
            )}
          </div>
        </section>
        <section className="mb-6">
          {/* <!-- HEADER --> */}
          <div className="flex items-center justify-between mb-3">
            <h4 className="text-base font-bold text-blue-700 flex items-center gap-2">
              ✍️ Tự luận
            </h4>
            <span className="text-xs px-2 py-0.5 rounded-full bg-blue-100 text-blue-700 font-semibold">
              {essay.length} câu
            </span>
          </div>

          {/* <!-- QUESTIONS --> */}
          <div className="space-y-4">
            {essay.map((q, index) => 
              <div className="bg-white border border-neutral-200 rounded-xl p-4 shadow-sm hover:shadow transition">
                
                {/* <!-- QUESTION --> */}
                <p className="text-sm font-semibold text-neutral-800 mb-3">
                  Câu {index + 1}. {q.question}
                </p>

                {/* <!-- ANSWER --> */}
                <div className="bg-blue-50 border border-blue-100 rounded-lg p-3 text-sm text-blue-800 leading-relaxed">
                  <span className="block text-xs font-semibold text-blue-600 mb-1">
                    Gợi ý / Đáp án:
                  </span>
                  <span className="pl-2 text-justify tracking-wide leading-relaxed whitespace-pre-line">{q.answer || "<i className='text-neutral-400'>Chưa có đáp án</i>"}</span>
                </div>
              </div>
            )}
          </div>
        </section>
        </>
      )
    }
    
    return <p className="text-sm text-gray-400">Bộ đề chưa có câu hỏi</p>
  }

  /* ================= XỬ LÝ NÚT CHỌN ĐỀ ================= */
  function handleCategory(e) {
    const cat = e.currentTarget.dataset.cat;
    if (!cat) return;
    // load dữ liệu
    loadDocuments(cat);
    setActive(cat);
  }
  
  useEffect(() => {
    loadDocuments(active);
  }, [active]);


  return(
    <div className="flex flex-col h-full">
      <div className="sticky top-0 px-5 z-30 backdrop-blur pt-2 pb-0 border-b mb-4 bg-white/95 border-neutral-100">
        <h1 className="text-2xl font-bold text-neutral-800 mb-3">📚 Tài liệu ôn tập</h1>
        <div className="relative mb-3">
          <input type="text" id="doc-search" placeholder="Tìm kiếm câu hỏi..." className="w-full pl-10 pr-4 py-2.5 border rounded-xl text-sm focus:bg-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition outline-none placeholder-neutral-400 bg-neutral-50 border-neutral-200" />
          <div className="absolute left-3 top-3 text-neutral-400">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
              <circle cx="11" cy="11" r="8"></circle>
              <path d="m21 21-4.3-4.3"></path>
            </svg>
          </div>
        </div>
        <div id="cat-filters" className="flex items-center gap-2 mb-3 overflow-x-auto no-scrollbar">
          <span className="text-[12px] font-bold uppercase tracking-wider text-neutral-400 shrink-0 mr-1">Bộ đề:</span>
          <button onClick={(e)=>handleCategory(e)} className={`cat-filter px-3 py-1.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${active==="all" ? "bg-neutral-900 text-white shadow-sm":"bg-white border border-neutral-200 text-neutral-600 hover:bg-neutral-50"}`} data-cat="all">Tất cả</button>
          <button onClick={(e)=>handleCategory(e)} className={`cat-filter px-3 py-1.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${active==="15p_hk1" ? "bg-neutral-900 text-white shadow-sm":"bg-white border border-neutral-200 text-neutral-600 hover:bg-neutral-50"}`} data-cat="15p_hk1">15 Phút</button>
          <button onClick={(e)=>handleCategory(e)} className={`cat-filter px-3 py-1.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${active==="hk1" ? "bg-neutral-900 text-white shadow-sm":"bg-white border border-neutral-200 text-neutral-600 hover:bg-neutral-50"}`} data-cat="hk1">Học Kỳ 1</button>
          <select id="cat-select" value={active} onChange={(e)=>{const value = e.target.value; setActive(value)}} className="ml-auto px-3 py-1.5 text-sm rounded-lg border border-neutral-200 bg-white text-neutral-700 focus:ring-2 focus:ring-indigo-500">
            <option value="">Bộ đề khác</option>
            <option value="15p_hk1">15' - HK1</option>
            <option value="1tiet_hk1">1Tiết - HK1</option>
            <option value="hk1">Học kỳ I</option>
            <option value="15p_hk2">15' - HK2</option>
            <option value="1tiet_hk2">1Tiết - HK2</option>
            <option value="hk2">Học kỳ II</option>
          </select>
        </div>
        <div className="flex items-center gap-2 mb-3 overflow-x-auto no-scrollbar pb-1 border-t border-dashed border-neutral-100 pt-2">
          <span className="text-[12px] font-bold uppercase tracking-wider text-neutral-400 shrink-0 mr-1">Dạng:</span>
          <button className="type-filter active px-3 py-1 rounded-md text-sm font-medium whitespace-nowrap transition-colors bg-indigo-50 text-indigo-700" data-type="all">Tất cả</button>
          <button className="type-filter px-3 py-1 rounded-md text-sm font-medium whitespace-nowrap transition-colors text-neutral-500 hover:bg-neutral-50 hover:text-neutral-900" data-type="mcq">Trắc nghiệm</button>
          <button className="type-filter px-3 py-1 rounded-md text-sm font-medium whitespace-nowrap transition-colors text-neutral-500 hover:bg-neutral-50 hover:text-neutral-900" data-type="essay">Tự luận</button>
        </div>
      </div>
      {isLoading && <Loading />}
      {items && <div id="doc-list" className="space-y-4 pb-20">
                  {renderDocs(items)}
                </div>}
      {isEmpty && <div id="doc-empty" className="flex flex-col items-center justify-center py-20 text-center">
        <div className="p-4 rounded-full mb-3 text-2xl bg-neutral-50">🔍</div>
        <p className="text-sm font-medium text-neutral-900">Không tìm thấy kết quả</p>
        <p className="text-xs text-neutral-500">Thử thay đổi bộ lọc hoặc từ khóa.</p>
      </div>}
    </div>
  )
}