import { useEffect, useRef } from "react";

export default function useSound() {
  const sounds = useRef({});

  useEffect(() => {
    sounds.current = {
      select: new Audio("https://luuchihoa.github.io/sound/click.mp3"),
      win: new Audio("https://luuchihoa.github.io/sound/win.mp3"),
      hover: new Audio("https://luuchihoa.github.io/sound/hover.mp3"),
      wrong: new Audio("https://luuchihoa.github.io/sound/buzzer.mp3"),
      correct: new Audio("https://luuchihoa.github.io/sound/ding.mp3"),
    };

    sounds.current.win.volume = 0.35;
    sounds.current.select.volume = 0.4;
    sounds.current.wrong.volume = 0.4;

    return () => {
      // cleanup khi unmount
      Object.values(sounds.current).forEach(sound => {
        sound.pause();
        sound.src = "";
      });
      sounds.current = {};
    };
  }, []);

  const play = (name, rate = 1) => {
    const audio = sounds.current[name];
    if (!audio) return;

    const sound = audio.cloneNode();
    sound.volume = audio.volume;
    sound.playbackRate = rate;

    sound.play().catch(() => {});
  };

  return { play };
}
