
import {useEffect, useState, useMemo} from "react";
import {GuideBox, ExitButton} from "./ui/Feedback.jsx";
import useSound from "./sound/useSounds.js";
import QuizContent from "./QuizContent.jsx";
import "./QuizBox.css";

export default function QuizBox({handleExit, config, quizData}) {
    const { play } = useSound();
    const [showGuide, setShowGuide] = useState(false);
    const [isOpenExit, setIsOpenExit] = useState(false);
    const [submitted, setSubmitted] = useState(false);
    const [key, setKey] = useState(0); // để reset component khi làm lại quiz

    const autoSubmit = () => {
        if (submitted) return;
        console.log("⏱ Auto submit quiz");
        setSubmitted(true);
    };
    
    useEffect(() => {
        const skipGuide = JSON.parse(localStorage.getItem("skipQuizGuide"));
        if (skipGuide) {
            setShowGuide(true);
        }
    }, []);
    const openGuide = () => {
        setShowGuide(false);
    }
    const openExitModal = () => {
        setIsOpenExit(true);
    }
    const handleReset = () => {
        play("select");
        setKey(prev => prev + 1);
        console.log("🔄 Resetting quiz");
        setSubmitted(false);
    }
    return (
        <div>
            {isOpenExit && <ExitButton handleExit={handleExit} handleClose={() => setIsOpenExit(false)} />}
            {!showGuide && <GuideBox setShowGuide={setShowGuide} />}
            <div className="relative w-[95vw] h-[80vh] sm:w-[92vw] sm:h-[90vh] md:w-[85vw] lg:w-[75vw] xl:w-[65vw] max-w-none bg-white glow-border shadow-2xl p-8 quiz-box">
                <div className="sticky top-0 flex justify-end pb-2">
                    <button onClick={openExitModal} className="absolute md:-top-2 md:-right-2 -top-6 -right-6 w-10 h-10 rounded-full bg-black/60 text-white hover:bg-red-600 flex items-center justify-center shadow-lg transition">✕</button>
                </div>
                <QuizContent key={key} config={config} quizData={quizData} autoSubmit={autoSubmit} submitted={submitted} handleReset={handleReset} openGuide={openGuide} />
            </div>
            <div className="fixed bottom-2 right-2 bg-black/80 text-white text-xs px-2 py-1 rounded pointer-events-none">Design by: Khối Phụng Vụ Gx An Ngãi</div>
        </div>
    )
}