function transferDateForView(value) {
    if (!value) return "";
    const dateObj = new Date(value);
    const day = String(dateObj.getDate()).padStart(2,"0");
    const month = String(dateObj.getMonth()+1).padStart(2,"0");
    const year = dateObj.getFullYear();
    return `${day}/${month}/${year}`;
}

export function ChangePassword ({setIsOpenChangePass}) {
    const { showToast } = useToast();
    const [oldPassword, setOldPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [saveLoading, setSaveLoading] = useState(false);
    const [toggleOldPassword, setToggleOldPassword] = useState(true);
    const [toggleNewPassword, setToggleNewPassword] = useState(true);
    const [toggleChangePassword, setToggleChangePassword] = useState(true);
  
    const closeChangePassword = () => {
        setIsOpenChangePass(false);
    }

    const submitChangePassword = async () => {
        const username = localStorage.getItem("username");
        if (!oldPassword || !newPassword || !confirmPassword)
            return showToast("Vui lòng nhập đầy đủ thông tin","warning");

        if (newPassword.length < 8)
            return showToast("Mật khẩu mới phải ≥ 8 ký tự","warning");

        if (newPassword !== confirmPassword)
            return showToast("Mật khẩu mới không khớp","warning");

        if (newPassword.includes(" "))
            return showToast("Mật khẩu không được chứa dấu cách","warning");

        setSaveLoading(true);

        try {
            const res = await fetch(API_URL, {
            method: "POST",
            body: JSON.stringify({
                action: "changePassword",
                username,
                oldPassword: oldPassword,
                newPassword: newPassword
            })
            });

            const data = await res.json();

            if (!data.success) {
                showToast("😑 Đổi mật khẩu thất bại","error");
                closeChangePassword();
                return;
            }
            showToast("✅ Đổi mật khẩu thành công","success");
            setSaveLoading(false);
            closeChangePassword();
        } 
        catch (err) {
            showToast("❌ Lỗi kết nối server","warning");
            console.error(err);
        }

    }

    return createPortal(
        <div id="modal-change-password" className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={saveLoading?undefined:closeChangePassword}>
            <div id="modal-change-password-box" className="w-full max-w-md mx-4 rounded-3xl bg-white p-6 shadow-2xl animate-scale-in" onClick={(e) => e.stopPropagation()}>
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-2">
                    <span className="text-2xl">🔒</span>
                    <h2 className="text-xl font-semibold text-gray-800">Đổi mật khẩu</h2>
                    </div>
                    <button onClick={closeChangePassword} className="text-gray-400 hover:text-gray-600 text-xl">✕</button>
                </div>
                <div className="space-y-5">
                    <div>
                    <label className="text-sm font-medium text-gray-600">Mật khẩu hiện tại</label>
                    <div className="relative mt-1">
                        <input id="oldPassword" type={toggleOldPassword?"password":"text"} placeholder="Nhập mật khẩu hiện tại" value={oldPassword} onChange={e => setOldPassword(e.target.value)} autoFocus
                            className="w-full rounded-xl border border-gray-200 px-4 py-2.5 pr-11 text-gray-800 placeholder-gray-400 focus:border-orange-400 focus:ring-2 focus:ring-orange-200 transition"/>
                        <button type="button" onClick={()=>setToggleOldPassword(!toggleOldPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-orange-500 transition">{toggleOldPassword?'👁️':'🙈'}</button>
                    </div>
                    </div>
                    <div>
                    <label className="text-sm font-medium text-gray-600">Mật khẩu mới</label>
                    <div className="relative mt-1">
                        <input id="newPassword" type={toggleNewPassword?"password":"text"} placeholder="Tối thiểu 8 ký tự" value={newPassword} onChange={e => setNewPassword(e.target.value)}
                        className="w-full rounded-xl border border-gray-200 px-4 py-2.5 pr-11
                                focus:border-orange-400 focus:ring-2 focus:ring-orange-200
                                transition" />
                        <button type="button" onClick={()=>setToggleNewPassword(!toggleNewPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-orange-500 transition">{toggleNewPassword?'👁️':'🙈'}</button>
                    </div>
                    </div>
                    <div>
                    <label className="text-sm font-medium text-gray-600">Nhập lại mật khẩu mới</label>
                    <div className="relative mt-1">
                        <input id="confirmPassword" type={toggleChangePassword?"password":"text"} placeholder="Nhập lại mật khẩu" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)}
                        className="w-full rounded-xl border border-gray-200 px-4 py-2.5 pr-11
                                focus:border-orange-400 focus:ring-2 focus:ring-orange-200
                                transition" />
                        <button type="button" onClick={()=>setToggleChangePassword(!toggleChangePassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-orange-500 transition">{toggleChangePassword?'👁️':'🙈'}</button>
                    </div>
                    </div>
                </div>
                <div className="mt-8 flex justify-end gap-3">
                    {!saveLoading && <button onClick={closeChangePassword} className="rounded-xl px-4 py-2 text-gray-600 hover:bg-gray-300 bg-gray-200 transition">Hủy</button>}
                    {<button disabled={saveLoading} id="savePasswordBtn" onClick={submitChangePassword} className={`relative overflow-hidden rounded-xl px-5 py-2
                            bg-orange-500 text-white font-medium
                            ${!saveLoading? "hover:bg-orange-600 active:scale-95":""}
                            transition flex items-center gap-2
                            disabled:opacity-70 disabled:cursor-not-allowed`}>
                    {saveLoading && <svg id="saveSpinner" className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v4a4 4 0 00-4 4H4z"></path>
                    </svg>}
                    {!saveLoading && <span id="saveBtnText">Lưu thay đổi</span>}
                    {saveLoading && <span id="saveBtnText">Đang lưu...</span>}
                    </button>}
                </div>
            </div>
        </div>,
        document.getElementById("modal-user")
    )
}

export function SaveBox ({setIsSaveBoxOn, user}) {
    const { showToast } = useToast();
    const [isSaveData, setIsSaveData] = useState(false);

    const confirmSave = async () => {
        setIsSaveData(true);
        try {
            const res = await fetch(`${API_URL}?action=updateprofile&data=${encodeURIComponent(JSON.stringify(user))}`);
            const result = await res.json();

        if (!result.success) {
            showToast("❌ Lưu dữ liệu thất bại","error");
            return;
        }

        } catch (err) {
            showToast("❌ Lỗi kết nối server","error");
            console.error(err);
        }
        showToast("✅ Lưu dữ liệu thành công","success");
        localStorage.setItem("user", JSON.stringify(user));
        closeConfirmSave();
        setIsSaveData(false);
    }

    const closeConfirmSave = () => {
        setIsSaveBoxOn(false);
    }

    return createPortal(
        <div id="confirm-save" className="fixed inset-0 z-[10000] bg-black/50 backdrop-blur-sm flex items-center justify-center">
            <div id="confirm-save-box" className="bg-white w-full max-w-sm mx-4 rounded-3xl p-6 shadow-2xl transition-all duration-300">
            <div className="flex justify-center mb-4">
                <div className="w-14 h-14 rounded-full bg-orange-100 flex items-center justify-center">
                <span className="text-3xl">💾</span>
                </div>
            </div>
            <h3 id="confirm-title" className="text-xl font-bold text-gray-800 mb-2 text-center">
                {!isSaveData && <span>Bạn muốn lưu thông tin không?</span>}
                {isSaveData && <span>⏳ Đang xử lý</span>}
            </h3>
            {!isSaveData && <p id="saveDataText" className="text-gray-500 mb-6 text-center leading-relaxed">Thông tin bạn vừa chỉnh sửa sẽ được cập nhật vào hệ thống.</p>}
            {isSaveData && <div id="save-loading" className="flex items-center justify-center gap-3 text-orange-500 mb-6">
                <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24" fill="none">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v4a4 4 0 00-4 4H4z"></path>
                </svg>
                <span className="font-medium">Đang lưu dữ liệu...</span>
            </div>}
            <div className="flex gap-3">
                <button id="btn-cancel-save" onClick={closeConfirmSave} className="flex-1 px-4 py-2.5 rounded-xl bg-gray-100 hover:bg-gray-200 text-gray-700 font-medium transition">Hủy</button>
                <button id="btn-confirm-save" onClick={confirmSave} className="flex-1 px-4 py-2.5 rounded-xl bg-orange-500 text-white font-semibold hover:bg-orange-600 active:scale-95 transition">Lưu</button>
            </div>
            </div>
        </div>,
        document.getElementById("modal-user")
    )
}

