export default function ModalUser({setIsLogin, handleClose}) {
    const { showToast } = useToast();
    const fileRef = useRef(null);
    const [loadingAva, setLoadingAva] = useState(false);
    const [avatarUrl, setAvatarUrl] = useState("");
    const [user, setUser] = useState({});
    const [switchTab, setSwitchTab] = useState('Profile');
    const [isSave, setIsSave] = useState(false);
    const [isOpenExit, setIsOpenExit] = useState(false);
    const [isAnyChange, setIsAnyChange] = useState(false);
    const studentData = useRef(null);
    
    const openExitButton = () => {
        isAnyChange?setIsOpenExit(true):handleClose();
    }

    const handleCloseButton = () => {
        setIsOpenExit(false);
    }

    const selectAvatar = () => {
        fileRef.current?.click();
    }

    const handleAvatar = async (e) => {
        const file = e.target.files?.[0];
        if (!file) 
            return;

        if (!file.type.startsWith("image/")) {
            showToast("Chỉ chọn ảnh","warning");
            return;
        }
        
        setLoadingAva(true);

        try {
            // 1️⃣ Resize ảnh
            const resizedBlob = await resizeImage(file, 300);

            // 2️⃣ Preview ngay bằng Blob URL
            const imgUrl = URL.createObjectURL(resizedBlob);
            setAvatarUrl(imgUrl);

            // 🔥 CHUYỂN SANG BASE64miệng
            const base64 = await blobToBase64(resizedBlob);

            // 3️⃣ Upload ảnh đã resize
            await uploadAvatar(base64);
        } catch (err) {
            console.error(err);
            showToast("Resize ảnh thất bại","error");
        } finally {
            setLoadingAva(false);
        }
    }

    //         <!-- Đặt lại kích thước ảnh -->
    const resizeImage = (file, maxSize = 300, quality = 0.85) => {
        return new Promise((resolve, reject) => {
            const img = new Image();
            const reader = new FileReader();

            reader.onload = () => {
            img.src = reader.result;
            };

            img.onload = () => {
            let { width, height } = img;

            // giữ tỉ lệ
            if (width > height) {
                if (width > maxSize) {
                height = height * (maxSize / width);
                width = maxSize;
                }
            } else {
                if (height > maxSize) {
                width = width * (maxSize / height);
                height = maxSize;
                }
            }

            const canvas = document.createElement("canvas");
            canvas.width = width;
            canvas.height = height;

            const ctx = canvas.getContext("2d");
            ctx.drawImage(img, 0, 0, width, height);

            canvas.toBlob(
                (blob) => {
                if (!blob) reject("Resize failed");
                resolve(blob);
                },
                "image/jpeg",
                quality
            );
            };

            reader.onerror = reject;
            reader.readAsDataURL(file);
        });
    }

    const blobToBase64 = (blob) => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = () => resolve(reader.result); // base64 string
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        });
    }

    const uploadAvatar = async (base64) => {
        const username = localStorage.getItem("username"); // lấy từ session/login thực tế

        // bỏ phần header "data:image/png;base64,"
        const pureBase64 = base64.split(",")[1];

        try {
            const res = await fetch("https://script.google.com/macros/s/AKfycbxGHSrh9HCFcKxfPqDnmYuMRxRHeoIeztowkZ6km8SKiJikm0AXioNWek97vhUlO6A/exec", {
            method: "POST",
            body: JSON.stringify({
                action: "updateAvatar",
                username,
                avatar: pureBase64
            })
            });

            const data = await res.json();

            if (data.success) {
                // ✅ đổi sang avatar thật từ Drive
                setUser(prev => ({
                    ...prev,
                    avatar : data.avatar
                }))
                showToast("Cập nhật avatar thành công","success");
            } else {
                showToast("Lỗi cập nhật avatar","warning");
            }
        } 
        catch (err) {
            console.error(err);
            showToast("Không thể upload avatar","error");
        }
    }

    useEffect(()=>{
        const savedData = JSON.parse(localStorage.getItem("user"));
        if(savedData) {
            setUser(savedData);
        }
        loadUser();
    },[isSave])

    // tránh memory leak khi preview ảnh bằng URL.createObjectURL
    useEffect(() => {
        return () => {
            if (avatarUrl) {
            URL.revokeObjectURL(avatarUrl);
            }
        };
    }, [avatarUrl]);

    const loadUser = async () => {
        const username = localStorage.getItem("username");
        if (!username) return;

        const res = await fetch(`${API_URL}?action=getUser&username=${username}`);
        const data = await res.json();

        setUser(data);
        localStorage.setItem("user", JSON.stringify(data));
        localStorage.setItem("avatar", data.avatar);
    }

    const handleLogout = () => {
        localStorage.removeItem("username");
        localStorage.removeItem("user");
        localStorage.removeItem("avatar");
        setUser({});
        setIsLogin(false);
    }
    
    return (
        <div id="modal-user" className="modal show" aria-hidden="false">
            <div className="fixed inset-0 z-[9999] bg-black/50 backdrop-blur-sm flex items-center justify-center" onClick={handleClose} >
                <div className="relative w-full max-w-4xl bg-white/90 backdrop-blur-xl rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.08)] py-4 px-2 md:p-8 max-h-[90vh] overflow-y-auto"  onClick={(e) => e.stopPropagation()} >
                    <button onClick={openExitButton} className="absolute top-4 right-4 z-[150] w-10 h-10 rounded-full bg-black/20 text-white hover:bg-red-600 flex items-center justify-center shadow-lg transition">✕</button>
                    {isOpenExit && <ExitButton handleClose={handleCloseButton} handleExit={handleClose}/>}
                    <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
                        <div className="relative self-center sm:order-2 px-8">
                            <div className={`relative w-20 h-20 sm:w-24 sm:h-24 rounded-full overflow-hidden ${loadingAva ? "opacity-70" : ""}`}>
                                <img src={user.avatar} className="w-full h-full object-cover border-4 border-orange-400 rounded-full"/>
                                {loadingAva && (<div className="absolute inset-0 z-10 flex items-center justify-center bg-black/40">
                                    <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin" />
                                </div>)}
                            </div>
                            <button onClick={selectAvatar} disabled={loadingAva} className={`absolute bottom-0 right-4 p-1.5 sm:p-2 rounded-full shadow
                                ${loadingAva ? "bg-gray-300 cursor-not-allowed" : "bg-orange-200 hover:bg-orange-400 text-gray-600" }`}>✏️</button>
                            <input type="file" ref={fileRef} accept="image/*" hidden onChange={handleAvatar}/>
                        </div>
                        <div className="flex flex-col sm:flex-row gap-2 bg-gray-100 rounded-xl p-1 sm:p-1.5 sm:order-1">
                            <button id="tabProfile" onClick={()=>setSwitchTab('Profile')} className={`w-full sm:w-auto px-4 py-2 rounded-lg text-sm font-semibold transition
                               ${switchTab === 'Profile'?"bg-white text-orange-600 shadow-sm ring-1 ring-orange-200":"text-gray-400 hover:text-orange-600 hover:bg-white/70"}`}>Hồ sơ cá nhân</button>
                            <button id="tabAchievement" onClick={()=>setSwitchTab('Achievement')} className={`w-full sm:w-auto px-4 py-2 rounded-lg text-sm font-semibold transition
                               ${switchTab === 'Achievement'?"bg-white text-orange-600 shadow-sm ring-1 ring-orange-200":"text-gray-400 hover:text-orange-600 hover:bg-white/70"}`}>Thành tích học tập</button>
                        </div>
                    </div>
                    {switchTab === 'Profile' && <Profile user={user} handleLogout={handleLogout} setUser={setUser} setIsSave={setIsSave} setIsAnyChange={setIsAnyChange}/>}
                    {switchTab === 'Achievement' && <Achievement user={user} studentData={studentData}/>}
                </div>
            </div>
        </div>
    )
}