import { createContext, useContext, useState, useCallback } from "react";

const ToastContext = createContext(null);

function Toast({ message, type }) {
  const TYPE_CLASS = {
    success: "bg-green-50 text-green-700 border border-green-300",
    error: "bg-red-50 text-red-700 border border-red-300",
    warning: "bg-yellow-50 text-yellow-800 border border-yellow-300",
    info: "bg-blue-50 text-blue-700 border border-blue-300"
  };

  return (
    <div
      className={`
        flex items-center gap-3 px-4 py-3 rounded-xl shadow-lg
        animate-slide-in
        ${TYPE_CLASS[type] || TYPE_CLASS.info}
      `}
    >
      <span className="text-sm font-medium ">{message}</span>
    </div>
  );
}

function ToastContainer({ toasts }) {
  return (
    <div className="fixed top-4 right-4 space-y-3 z-[9999]">
      {toasts.map(t => (
        <Toast key={t.id} {...t} />
      ))}
    </div>
  );
}

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);

  const showToast = useCallback((message, type = "info", duration = 3000) => {
    const id = Date.now();

    setToasts(prev => [...prev, { id, message, type }]);

    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, duration);
  }, []);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      <ToastContainer toasts={toasts} />
    </ToastContext.Provider>
  );
}

export function useToast() {
  return useContext(ToastContext);
}
