import {useState, useEffect, useMemo, useRef} from "react";
import QuizTimer from "./ui/Timer.jsx";
import useSound from "./sound/useSounds.js";

// ====================== TIỆN ÍCH =========================
function getRandomItems(arr, n) {
  return [...arr].sort(() => 0.5 - Math.random()).slice(0, n);
}

// ====================== HIỆU ỨNG NHẸ (không bắt buộc) =========================
function createFirefly(x, y) {
  const firefly = document.createElement("div");
  firefly.classList.add("firefly", "w-2", "h-2", "bg-yellow-400", "rounded-full", "absolute", "pointer-events-none");
  firefly.style.left = x + "px";
  firefly.style.top = y + "px";
  const dx = (Math.random() - 0.5) * 150;
  const dy = (Math.random() - 0.5) * 150;
  firefly.animate([{ transform: `translate(0,0)`, opacity: 1 }, { transform: `translate(${dx}px,${dy}px)`, opacity: 0 }], { duration: 2000 + Math.random() * 1000, easing: "ease-out" });
  document.body.appendChild(firefly);
  setTimeout(() => firefly.remove(), 1200);
}

function createFirework(x, y) {
  const particles = 16;
  const radius = 100;
  for (let i = 0; i < particles; i++) {
    const angle = (Math.PI * 2 * i) / particles;
    const fx = x + Math.cos(angle) * radius;
    const fy = y + Math.sin(angle) * radius;
    const spark = document.createElement("div");
    spark.classList.add("firework", "w-2", "h-2", "rounded-full", "absolute");
    spark.style.background = `hsl(${Math.random() * 360}, 90%, 60%)`;
    spark.style.left = x + "px";
    spark.style.top = y + "px";
    spark.animate([{ transform: `translate(0,0) scale(1)`, opacity: 1 }, { transform: `translate(${fx - x}px, ${fy - y}px) scale(0.3)`, opacity: 0 }], { duration: 400, easing: "ease-out" });
    document.body.appendChild(spark);
    setTimeout(() => spark.remove(), 900);
    setTimeout(() => { createFirefly(fx, fy); createFirefly(fx, fy); }, 0);
  }
}
export function Mcq({setMcqScore, mcq, setType, config, setUserAnswers}) {
    const [submitted, setSubmitted] = useState(false);
    const [selectedKey, setSelectedKey] = useState(null);
    const optionRefs = useRef({});
    const scoreRef = useRef(0);

    const { play } = useSound();

    let [current, setCurrent] = useState(0);

    const isMobile = useMemo(
        () => /Android|iPhone|iPad/i.test(navigator.userAgent),
        []
    );
    const handleAnswer = (key = "Không trả lời") => {
        if (submitted) return;
        setSelectedKey(key);
        if (!q) return;
        setUserAnswers(prev => [
        ...prev,
        {
            question: q.text,
            selected: key,
            correct: q.correct
        }
        ]);
        key === "Không trả lời" ? play("select") : key!==q.correct ? play("wrong") : play("correct");
        const correctEl = optionRefs.current[q.correct];
        if (key === q.correct) {
            scoreRef.current += 1;
            const rect = correctEl.getBoundingClientRect();
            createFirework(rect.left + rect.width / 2, rect.top + rect.height / 2);
        }
        setSubmitted(true);

        setTimeout(() => {
            setSubmitted(false);
            setSelectedKey(null);
            setCurrent(prev => prev + 1)

            if(current === mcq.length - 1){
                setMcqScore((scoreRef.current*config.mcqPoint/mcq.length).toFixed(2));
                setType("essay");
            }
        }
        , 1200);
    };
    // dùng âm thanh: play("select"), play("correct"), play("wrong"), play("hover"), play("win")

    const q = mcq?.[current];
    if (!q) {
        return (
        <p className="text-gray-500 text-center">
            Không có câu hỏi
        </p>
        );
    }
    return (
    <div id="quiz-content">
        <h5 className="text-xl md:text-2xl font-bold text-gray-800 mb-4">
            Câu {current + 1}: {q.text}
        </h5>

        <div className="space-y-3">
            {Object.entries(q.choices || {}).map(([k, v]) => {
                const isCorrect = submitted && k === q.correct;
                const isWrong = submitted && k !== q.correct && selectedKey === k;
                return (
            <div
                key={k}
                ref={el=> optionRefs.current[k]=el}
                className={`option text-base cursor-pointer ${submitted ? "pointer-events-none" : ""}
                    ${isCorrect ? "correct" : ""} ${isWrong ? "wrong" : ""}`}
                onClick={() => handleAnswer(k)}
                onMouseEnter={() => !isMobile && play("hover")}
            >
                <span className="option-circle">{k}</span>
                <span className="option-text">{v}</span>
            </div>
            )})}
        </div>

        <button
            className={`skipBtn mt-4 w-full py-3 bg-gray-200 rounded-xl hover:bg-gray-300 font-bold transition ${submitted ? "pointer-events-none" : ""}`}
            onClick={() => handleAnswer()}
        >
            Câu tiếp theo
        </button>
        </div>
    );

}
export function Essay({essay, setType, setEssayScore, config, setUserEssayAns}) {
    const { play } = useSound();
    const ansRefs = useRef({});
    const essayRef = useRef(0);
    const checkEssay = () => {
        play("win");
        essay.forEach((q, i) => {
            const ansRef = ansRefs.current[`essay${i}`];
            const ans = ansRef?.value.toLowerCase() || "Không trả lời";
            setUserEssayAns(prev => ({...prev, [`essay${i}`]: ans}));
            let score = 0;
            (q.keywords || []).forEach(item => {
            const keyLower = (item.word || []).map(w => w.toLowerCase());
            if (keyLower.every(w => ans.includes(w))) score += (config.essayPoint / (config.essayCount || 1) / (q.keywords.length || 1));
            });
            essayRef.current += score;
        });
        setEssayScore(essayRef.current.toFixed(2));
        setType("result");
    }
    
    return (
        <div>
            {essay.map((q, i) => {
                return (
                    <div key={i}>
                        <h5 className="mt-3 text-lg font-semibold">{i + 1}. {q.text}</h5>
                        <textarea ref={el => ansRefs.current[`essay${i}`] = el} className="w-full p-3 border border-gray-300 rounded-xl mt-2" rows="4" placeholder="Nhập câu trả lời của bạn..."></textarea>
                    </div>
                );
            })}
            <button id="submitEssay" onClick={checkEssay} className="mt-4 w-full py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-bold transition">Nộp bài</button>
        </div>
    )
    
}
export function Result({mcq, essay, mcqScore, essayScore, userAnswers, handleReset, userEssayAns}) {
    // ====================== SEND DATA =========================
    async function sendData(username="anonymous", value=0) {
        const data = { user: username, value: value };
        const API_URL = "https://script.google.com/macros/s/AKfycbxi7H5MhkxM478EnIX-shg1NMxg4ljIyCcokmODv55zBnNLyTBtkKTGG-brJcSmf5Q/exec";
        try {
            await fetch(API_URL, { method: "POST", mode: "no-cors", body: JSON.stringify(data) });
        } catch (e) { /* ignore errors from no-cors */ }
    }
    const total = (parseFloat(essayScore)+parseFloat(mcqScore)).toFixed(2);
    // Send data safely (non-blocking)
    useEffect(() => {
        try {
            sendData(localStorage.username, total);
        } catch (e) {
            // ignore
        }
    }, []);
    // ====================== HIỂN THỊ KẾT QUẢ =========================
    const mcqReview = (mcq || []).map((q, i) => {
        const ua = userAnswers[i];
        const selected = ua ? ua.selected : null;
        const selectedText = selected && selected !== "Không trả lời" ? q.choices[selected] : (selected === "Không trả lời" ? "Không trả lời" : "Chưa trả lời");
        const correctText = q.choices[q.correct];
        let statusClass = "text-gray-500";
        if (selected === q.correct) statusClass = "text-green-600 font-bold";
        else if (selected === "Không trả lời") statusClass = "text-gray-400";
        else statusClass = "text-red-600 font-bold";

        return (
            <div className="p-3 mb-3 border rounded-xl bg-gray-50">
                <p><strong>Câu {i + 1}. {q.text}</strong></p>
                <p>Đáp án của bạn: <span className={`${statusClass}`}>{selectedText}</span></p>
                <p>Đáp án đúng: <strong className="text-green-700">{correctText}</strong></p>
            </div>
        )
    });

    const essayReview = (essay || []).map((q, i) => {
        const ans = userEssayAns[`essay${i}`];
        return (
            <div className="p-3 mb-3 border rounded-xl bg-gray-50">
                <div>
                    <strong>Câu {i + 1}. {q.text}</strong>
                    <br />

                    <span className="text-green-600">
                    {(q.sample || "").split("\n").map((line, idx) => (
                        <div key={idx}>{line}</div>
                    ))}
                    </span>
                </div>

                <div className="mt-2">
                    <strong>Câu trả lời của bạn:</strong>
                    <br />
                    <span>{ans}</span>
                </div>
            </div>
        )
    });

  return ( 
    <>
        <h1 className="text-3xl text-center text-green-600 mb-3 font-bold">Hoàn thành bài kiểm tra!</h1>
        <p className="text-center text-lg">Điểm trắc nghiệm: {mcqScore}/5</p>
        <p className="text-center text-lg">Điểm tự luận: {essayScore}/5</p>
        <hr className="my-4" />
        <p className="text-center text-xl font-bold text-red-600">Tổng điểm: {(parseFloat(essayScore)+parseFloat(mcqScore)).toFixed(2)}/10</p>
        <h4 className="mt-4 text-lg font-semibold">Xem lại phần trắc nghiệm:</h4>
            {mcqReview}
        <h4 className="mt-4 text-lg font-semibold">Xem lại phần tự luận:</h4>
            {essayReview}
        <div className="text-center mt-3">
            <button className="py-2 px-6 bg-gray-400 text-white rounded-xl hover:bg-gray-500 transition" onClick={handleReset}>Làm lại</button>
        </div>
    </>
  )
}
export default function QuizContent({config, quizData, autoSubmit, submitted, handleReset, openGuide}) {
    const [mcqScore, setMcqScore] = useState(0);
    const [essayScore, setEssayScore] = useState(0);
    const [userAnswers, setUserAnswers] = useState([]);
    const [userEssayAns, setUserEssayAns] = useState({});
    // ====================== HIỂN THỊ NỘI DUNG =========================
    const [type, setType] = useState("mcq"); // mcq, essay, result
    const showMap = {
        mcq: Mcq,
        essay: Essay,
        result: Result,
    };
    const ShowContent = showMap[type];
    // ====================== DỮ LIỆU =========================
    let questions = quizData.mcq;
    let essayQuestions = quizData.essay;
    
    if (!config) {
        console.error("initQuiz: exam type không hợp lệ:", type);
        return;
    }
    
    useEffect(() => {
        if (submitted) {
            console.log("📤 QuizContent nhận autoSubmit");
            // xử lý nộp bài
        }
    }, [submitted]);

    // Lấy câu hỏi ngẫu nhiên dựa trên config
    const mcq = useMemo(() => {
    if (!questions?.length) return [];
    return getRandomItems(questions, config.mcqCount || 0);
    }, [questions, config.mcqCount]);

    const essay = useMemo(() => {
    if (!essayQuestions?.length) return [];
    return getRandomItems(essayQuestions, config.essayCount || 0);
    }, [essayQuestions, config.essayCount]);

    return(
        <>
            {type !== "result" && <h1 className="header-quiz title-quiz text-2xl md:text-4xl font-extrabold text-center text-orange-500 mb-4">ÔN TẬP 15 PHÚT</h1>}
            {type === "mcq" && <h2 className="text-2xl section-title text-gray-500 font-semibold mb-6 text-center">Phần I: Trắc Nghiệm</h2>}
            {type === "essay" && <h2 className="text-2xl section-title text-gray-500 font-semibold mb-6 text-center">Phần II: Tự Luận</h2>}
            <ShowContent handleReset={handleReset} setType={setType} mcq={mcq} essay={essay} setMcqScore={setMcqScore} setEssayScore={setEssayScore} mcqScore={mcqScore} essayScore={essayScore} autoSubmit={autoSubmit} submitted={submitted} config={config} setUserAnswers={setUserAnswers} userAnswers={userAnswers} setUserEssayAns={setUserEssayAns} userEssayAns={userEssayAns} />
            {type !== "result" && <div className="relative mt-6 mx-auto w-fit">
                <div className="digital-clock mt-6 mx-auto w-fit flex items-center gap-3
                    px-5 py-3 rounded-full
                    bg-gradient-to-r from-orange-100 to-orange-200
                    shadow-lg">
                <span className="text-xl font-semibold text-orange-600">⏱ Thời gian</span>
                <QuizTimer duration={config.time} onTimeUp={autoSubmit}/>
                </div>
                <button onClick={openGuide} className="absolute -right-12 top-1/2 -translate-y-1/2 w-9 h-9 rounded-full bg-orange-500 text-white flex items-center justify-center font-bold shadow-lg hover:bg-orange-600 transition active:scale-95" title="Hướng dẫn">?</button>
            </div>}
        </>
    )
}