import { useEffect, useState } from "react";
import { useToast } from "./ToastContext.jsx";

 
export default function ModalLogin({ handleClose, setIsLogin}) {
  const API_URL = 'https://script.google.com/macros/s/AKfycbxGHSrh9HCFcKxfPqDnmYuMRxRHeoIeztowkZ6km8SKiJikm0AXioNWek97vhUlO6A/exec';
  const [password, setPassword] = useState("");
  const [username, setUsername] = useState("");
  const { showToast } = useToast();

  const handleLogin = async function () {
    
    if (!username || !password) {
      showToast("⚠️ Vui lòng nhập đầy đủ thông tin","warning");
      return;
    }

    showToast('Đang kiểm tra...');

    const res = await fetch(
      `${API_URL}?action=login&username=${encodeURIComponent(username)}&password=${encodeURIComponent(password)}`
    );
    const result = await res.json();
    if (result.success) {
      showToast("✅ Đăng nhập thành công","success");
      localStorage.setItem("sessionKey", result.sessionKey);
      localStorage.setItem("username", result.username);
      localStorage.setItem("role", result.role);
      setIsLogin(true);
    } else {
      showToast("❌ Sai tài khoản hoặc mật khẩu","error");
    }
  };

  return (
    <div id="modal-login" className="fixed inset-0 z-[9999] bg-black/50 backdrop-blur-sm flex items-center justify-center"
      onClick={handleClose} >
      {/* BOX */}
      <div className="bg-white w-full max-w-sm mx-4 rounded-3xl p-6 shadow-2xl" onClick={(e) => e.stopPropagation()} >
        {/* HEADER */}
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-gray-800">🔐 Đăng nhập</h2>
          <button className="text-gray-400 hover:text-red-500 text-xl" onClick={handleClose}>✕</button>
        </div>
        {/* FORM */}
        <div className="space-y-4">
          <input type="text" placeholder="Tên đăng nhập" value={username} onChange={(e) => setUsername(e.target.value)} className="w-full px-4 py-2.5 rounded-xl border focus:outline-none focus:ring-2 focus:ring-orange-400"/>
          <input type="password" placeholder="Mật khẩu" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-4 py-2.5 rounded-xl border focus:outline-none focus:ring-2 focus:ring-orange-400"/>
          <button onClick={handleLogin} className="w-full py-2.5 rounded-xl bg-orange-500 text-white font-semibold hover:bg-orange-600 active:scale-95 transition">
            Đăng nhập
          </button>
        </div>
      </div>
    </div>
  );
}
